DROP TABLE IF EXISTS `paynpik_kitchen_stations`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `paynpik_kitchen_stations` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `isActive` tinyint(1) NOT NULL DEFAULT '1',
  `isMaster` tinyint(1) NOT NULL DEFAULT '0',
  `outletId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `currentWorkerId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updatedAt` datetime(3) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `kitchen_stations_outletId_fkey` (`outletId`),
  KEY `kitchen_stations_currentWorkerId_fkey` (`currentWorkerId`),
  CONSTRAINT `kitchen_stations_currentWorkerId_fkey` FOREIGN KEY (`currentWorkerId`) REFERENCES `paynpik_users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `kitchen_stations_outletId_fkey` FOREIGN KEY (`outletId`) REFERENCES `paynpik_outlets` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
