DROP TABLE IF EXISTS `paynpik_orders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `paynpik_orders` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `orderNumber` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `tokenNumber` int DEFAULT NULL,
  `status` enum('CREATED','QUEUED','PREPARING','READY','OUT_FOR_SERVICE','SERVED','CANCELLED','DISPUTED','RESOLVED','FOR_REFUND','REFUND_COMPLETE') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'CREATED',
  `isParcel` tinyint(1) NOT NULL DEFAULT '0',
  `notes` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `subtotal` decimal(10,2) NOT NULL,
  `taxAmount` decimal(10,2) NOT NULL DEFAULT '0.00',
  `sgstAmount` decimal(10,2) NOT NULL DEFAULT '0.00',
  `cgstAmount` decimal(10,2) NOT NULL DEFAULT '0.00',
  `parcelAmount` decimal(10,2) NOT NULL DEFAULT '0.00',
  `discountAmount` decimal(10,2) NOT NULL DEFAULT '0.00',
  `totalAmount` decimal(10,2) NOT NULL,
  `outletId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `sectionId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tableId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `customerId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `staffId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updatedAt` datetime(3) NOT NULL,
  `billRequestedAt` datetime(3) DEFAULT NULL,
  `isPostpaid` tinyint(1) NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  UNIQUE KEY `orders_orderNumber_key` (`orderNumber`),
  KEY `orders_outletId_fkey` (`outletId`),
  KEY `orders_sectionId_fkey` (`sectionId`),
  KEY `orders_tableId_fkey` (`tableId`),
  KEY `orders_customerId_fkey` (`customerId`),
  KEY `orders_staffId_fkey` (`staffId`),
  CONSTRAINT `orders_customerId_fkey` FOREIGN KEY (`customerId`) REFERENCES `paynpik_users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `orders_outletId_fkey` FOREIGN KEY (`outletId`) REFERENCES `paynpik_outlets` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `orders_sectionId_fkey` FOREIGN KEY (`sectionId`) REFERENCES `paynpik_sections` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `orders_staffId_fkey` FOREIGN KEY (`staffId`) REFERENCES `paynpik_users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `orders_tableId_fkey` FOREIGN KEY (`tableId`) REFERENCES `paynpik_tables` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

