  CONSTRAINT `user_responsibilities_responsibilityId_fkey` FOREIGN KEY (`responsibilityId`) REFERENCES `paynpik_responsibilities` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `user_responsibilities_userId_fkey` FOREIGN KEY (`userId`) REFERENCES `paynpik_users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
